mapper.select:
SELECT wr.id, wr.equipment_id, e.equipment_number, e.equipment_name, wr.warehouse_id, w.warehouse_name, wr.supplier_id, s.supplier_name, wr.record_type, CASE WHEN wr.record_type = 1 THEN '入库' WHEN wr.record_type = 2 THEN '出库' ELSE '' END AS type_text, wr.quantity, SUM(CASE WHEN sub.record_type = 1 THEN sub.quantity ELSE -sub.quantity END) AS stock_quantity, wr.operator_id, u.real_name AS operator_name, wr.remark, wr.create_time FROM warehouse_record wr LEFT JOIN equipment e ON wr.equipment_id = e.id LEFT JOIN warehouse w ON wr.warehouse_id = w.id LEFT JOIN supplier s ON wr.supplier_id = s.id LEFT JOIN sys_user u ON wr.operator_id = u.id LEFT JOIN warehouse_record sub ON sub.equipment_id = wr.equipment_id AND sub.create_time <= wr.create_time
AND wr.equipment_id = #{equipmentId}
AND wr.warehouse_id = #{warehouseId}
AND wr.supplier_id = #{supplierId}
AND wr.record_type = #{recordType}
AND (e.equipment_name LIKE CONCAT('%', #{keyword}, '%') OR e.equipment_number LIKE CONCAT('%', #{keyword}, '%'))
GROUP BY wr.id, wr.equipment_id, e.equipment_number, e.equipment_name, wr.warehouse_id, w.warehouse_name, wr.supplier_id, s.supplier_name, wr.record_type, wr.quantity, wr.operator_id, u.real_name, wr.remark, wr.create_time ORDER BY wr.create_time DESC

