AND wr.warehouse_id = #{warehouseId}
AND wr.record_type = #{recordType}
AND wr.equipment_id = #{equipmentId}
AND (e.equipment_name LIKE CONCAT('%', #{keyword}, '%') OR e.equipment_number LIKE CONCAT('%', #{keyword}, '%'))
GROUP BY wr.id, wr.equipment_id, e.equipment_number, e.equipment_name, wr.warehouse_id, w.warehouse_name, wr.supplier_id, s.supplier_name, wr.record_type, wr.quantity, wr.operator_id, u.real_name, wr.remark, wr.create_time ORDER BY wr.create_time DESC
